function uf_handle_upload() {
    $upload_dir = wp_upload_dir();
    $target_dir = $upload_dir['basedir'] . '/user-files/';
    if (!file_exists($target_dir)) {
        wp_mkdir_p($target_dir);
    }

    foreach ($_FILES['user_file']['name'] as $key => $name) {
        $file_tmp = $_FILES['user_file']['tmp_name'][$key];
        $file_type = $_FILES['user_file']['type'][$key];
        $file_size = $_FILES['user_file']['size'][$key];

        $allowed_types = array('image/jpeg', 'image/png', 'image/gif', 'application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document');

        if (in_array($file_type, $allowed_types) && $file_size < 2000000) { // Limit size to 2MB
            $file_name = basename($name);
            $target_file = $target_dir . $file_name;

            if (move_uploaded_file($file_tmp, $target_file)) {
                echo "The file " . htmlspecialchars($file_name) . " has been uploaded.";
            } else {
                echo "Sorry, there was an error uploading your file.";
            }
        } else {
            echo "Invalid file type or size.";
        }
    }
}

